use crate::model::State;

pub fn mote_e(a: &State, b: &str, c: &str, d: &str) -> (String, String) {
    // Walk from requesting subject toward grantors following the delegation chain.
    // If any subject along this walk is blocked/revoked, delegated access denies.
    let mut current = b.to_string();
    let mut path: Vec<String> = vec![current.clone()];

    loop {
        if a.direct.contains(&(current.clone(), c.to_string(), d.to_string())) {
            let delegated = current != b;
            if delegated {
                // Deny if any subject along the delegation chain is blocked/revoked.
                if path.iter().any(|s| a.blocked.contains(s)) {
                    return ("deny".to_string(), String::new());
                }
                // blocked/revoked subjects never receive allow on delegated paths.
                if a.blocked.contains(b) {
                    return ("deny".to_string(), String::new());
                }
                // delegated_from = grantor (the subject holding the direct grant)
                return ("allow".to_string(), current);
            }

            // Direct grant.
            return ("allow".to_string(), String::new());
        }

        match a.chain.get(&current) {
            Some(parent) => {
                current = parent.clone();
                path.push(current.clone());
            }
            None => return ("deny".to_string(), String::new()),
        }
    }
}
